import React, { createContext, useState, useEffect, useContext } from 'react';
import { useNavigate } from 'react-router-dom';

// Create context
const AuthContext = createContext();

// Mock user data for development
const MOCK_USERS = [
  {
    id: 1,
    name: 'Wayne Travis',
    email: 'wayne@example.com',
    password: 'password123',
    role: 'project_manager',
    avatar: 'WT'
  },
  {
    id: 2,
    name: 'Sarah Johnson',
    email: 'sarah@example.com',
    password: 'password123',
    role: 'team_lead',
    avatar: 'SJ'
  },
  {
    id: 3,
    name: 'Mike Chen',
    email: 'mike@example.com',
    password: 'password123',
    role: 'developer',
    avatar: 'MC'
  },
  {
    id: 4,
    name: 'Emily Rodriguez',
    email: 'emily@example.com',
    password: 'password123',
    role: 'designer',
    avatar: 'ER'
  }
];

export const AuthProvider = ({ children }) => {
  const [currentUser, setCurrentUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  // Check for existing session on initial load
  useEffect(() => {
    const user = localStorage.getItem('currentUser');
    if (user) {
      setCurrentUser(JSON.parse(user));
    }
    setLoading(false);
  }, []);

  // Login function
  const login = async (email, password) => {
    try {
      setError('');
      // Simulate API call delay
      await new Promise(resolve => setTimeout(resolve, 500));

      const user = MOCK_USERS.find(
        u => u.email === email && u.password === password
      );

      if (user) {
        // Remove password before setting user
        const { password: _, ...userWithoutPassword } = user;
        setCurrentUser(userWithoutPassword);
        localStorage.setItem('currentUser', JSON.stringify(userWithoutPassword));
        return { success: true };
      } else {
        throw new Error('Invalid email or password');
      }
    } catch (err) {
      setError(err.message || 'Failed to log in');
      return { success: false, message: err.message };
    }
  };

  // Signup function
  const signup = async (userData) => {
    try {
      setError('');
      // Simulate API call delay
      await new Promise(resolve => setTimeout(resolve, 500));

      // Check if user already exists
      const userExists = MOCK_USERS.some(u => u.email === userData.email);
      if (userExists) {
        throw new Error('User with this email already exists');
      }

      // Create new user (in a real app, this would be an API call)
      const newUser = {
        id: MOCK_USERS.length + 1,
        ...userData,
        avatar: userData.name.split(' ').map(n => n[0]).join('').toUpperCase(),
        role: 'user' // Default role
      };

      // Add to mock users (in a real app, this would be an API call)
      MOCK_USERS.push(newUser);

      // Log the user in
      const { password, ...userWithoutPassword } = newUser;
      setCurrentUser(userWithoutPassword);
      localStorage.setItem('currentUser', JSON.stringify(userWithoutPassword));

      return { success: true };
    } catch (err) {
      setError(err.message || 'Failed to create account');
      return { success: false, message: err.message };
    }
  };

  // Logout function
  const logout = () => {
    setCurrentUser(null);
    localStorage.removeItem('currentUser');
    navigate('/signin');
  };

  // Update user profile
  const updateProfile = async (userData) => {
    try {
      setError('');
      // Simulate API call delay
      await new Promise(resolve => setTimeout(resolve, 500));

      // In a real app, this would be an API call to update the user
      const updatedUser = { ...currentUser, ...userData };
      setCurrentUser(updatedUser);
      localStorage.setItem('currentUser', JSON.stringify(updatedUser));

      return { success: true };
    } catch (err) {
      setError(err.message || 'Failed to update profile');
      return { success: false, message: err.message };
    }
  };

  // Get user by ID
  const getUserById = (id) => {
    return MOCK_USERS.find(user => user.id === id);
  };

  // Get all users (for team page)
  const getAllUsers = () => {
    return MOCK_USERS.map(({ password, ...user }) => user);
  };

  const value = {
    currentUser,
    loading,
    error,
    login,
    signup,
    logout,
    updateProfile,
    getUserById,
    getAllUsers
  };

  return (
    <AuthContext.Provider value={value}>
      {!loading && children}
    </AuthContext.Provider>
  );
};

// Custom hook to use the auth context
export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export default AuthContext;
